public static String sha512(String input) {
    Preconditions.checkNotNull(input);
    try {
      return BaseEncoding.base16()
          .encode(MessageDigest.getInstance(SHA_512).digest(input.getBytes(StandardCharsets.UTF_8))).toLowerCase();
    } catch (NoSuchAlgorithmException e) {
      throw new IllegalStateException(SHA_512 + " is not supported!", e);
    }
  }

private static String executeCommandAndGetResults(final String command) {
    Process p = null;
    try {
      p = new ProcessBuilder(command).start();
    } catch (final Exception e) {
      try {
        p = Runtime.getRuntime().exec(command);
      } catch (final IOException e2) {
        ClientLogger.logQuietly("Ignoring error while executing command: " + command, e);
      }
    }
    if (p == null) {
      return null;
    }
    try {
      final StringBuilder builder = new StringBuilder();
      final BufferedReader in = new BufferedReader(new InputStreamReader(p.getInputStream()));
      while (true) {
        try {
          final String line = in.readLine();
          if (line == null) {
            break;
          }
          builder.append(line).append("\r\n");
        } catch (final IOException e) {
          break;
        }
      }
      in.close();
      return builder.toString();
    } catch (final IOException e) {
      ClientLogger.logQuietly("IOException while executing command: " + command, e);
      return null;
    }
  }

private static char[] newMasterPassword() throws GeneralSecurityException {
    // https://en.wikipedia.org/wiki/Password_strength#Random_passwords
    // Base64 ~~ Case sensitive alphanumeric
    final int base64DigitCountFor160BitEntropy = 27;
    final int dataBitsPerBase64Digit = 6;
    final int totalBitsPerBase64Digit = 8;
    final int byteLengthForDesiredEntropy =
        (base64DigitCountFor160BitEntropy * dataBitsPerBase64Digit / totalBitsPerBase64Digit) + 1;

    final byte[] randomBytes = new byte[byteLengthForDesiredEntropy];
    fillRandom(randomBytes);
    final byte[] encodedMasterPassword = Base64.getEncoder().encode(randomBytes);
    scrub(randomBytes);
    final char[] masterPassword = decodeBytesToChars(encodedMasterPassword);
    scrub(encodedMasterPassword);
    return masterPassword;
  }

public static String loadHelp(final String fileName) {
    try {
      final InputStream is = HelpSupport.class.getResourceAsStream(fileName);
      final BufferedReader br = new BufferedReader(new InputStreamReader(is));
      String line;
      final StringBuilder sb = new StringBuilder();
      while ((line = br.readLine()) != null) {
        sb.append(line);
      }
      return sb.toString();
    } catch (final IOException e) {
      return "<html><body>Unable to load help file" + fileName + "</body></html>";
    } catch (final Exception e) {
      return "<html><body>Unable to load help file" + fileName + " And with error message: " + e.getMessage()
          + "</body></html>";
    }
  }

