private void testEmail() {
    final ProgressWindow progressWindow = GameRunner.newProgressWindow("Sending test email...");
    progressWindow.setVisible(true);
    final Runnable runnable = () -> {
      // initialize variables to error state, override if successful
      String message = "An unknown occurred, report this as a bug on the TripleA dev forum";
      int messageType = JOptionPane.ERROR_MESSAGE;
      try {
        final String html = "<html><body><h1>Success</h1><p>This was a test email sent by TripleA<p></body></html>";
        final File dummy = new File(ClientFileSystemHelper.getUserRootFolder(), "dummySave.txt");
        dummy.deleteOnExit();
        final FileOutputStream fout = new FileOutputStream(dummy);
        fout.write("This file would normally be a save game".getBytes());
        fout.close();
        ((IEmailSender) getBean()).sendEmail("TripleA Test", html, dummy, "dummy.txt");
        // email was sent, or an exception would have been thrown
        message = "Email sent, it should arrive shortly, otherwise check your spam folder";
        messageType = JOptionPane.INFORMATION_MESSAGE;
      } catch (final IOException ioe) {
        message = "Unable to send email: " + ioe.getMessage();
      } finally {
        // now that we have a result, marshall it back unto the swing thread
        final String finalMessage = message;
        final int finalMessageType = messageType;
        SwingUtilities.invokeLater(() -> {
          try {
            GameRunner.showMessageDialog(
                finalMessage,
                GameRunner.Title.of("Email Test"),
                finalMessageType);
          } catch (final HeadlessException e) {
            // should never happen in a GUI app
          }
        });
        progressWindow.setVisible(false);
      }
    };
    // start a background thread
    final Thread t = new Thread(runnable);
    t.start();
  }

@Override
  public void sendEmail(final String subject, final String htmlMessage, final File saveGame, final String saveGameName)
      throws IOException {
    // this is the last step and we create the email to send
    if (m_toAddress == null) {
      throw new IOException("Could not send email, no To address configured");
    }
    final Properties props = new Properties();
    if (getUserName() != null) {
      props.put("mail.smtp.auth", "true");
    }
    if (m_encryption == Encryption.TLS) {
      props.put("mail.smtp.starttls.enable", "true");
      props.put("mail.smtp.starttls.required", "true");
    }
    props.put("mail.smtp.host", getHost());
    props.put("mail.smtp.port", getPort());
    props.put("mail.smtp.connectiontimeout", m_timeout);
    props.put("mail.smtp.timeout", m_timeout);
    final String to = m_toAddress;
    final String from = "noreply@triplea-game.org";
    // todo get the turn and player number from the game data
    try {
      final Session session = Session.getInstance(props, null);
      final MimeMessage mimeMessage = new MimeMessage(session);
      // Build the message fields one by one:
      // priority
      mimeMessage.setHeader("X-Priority", "3 (Normal)");
      // from
      mimeMessage.setFrom(new InternetAddress(from));
      // to address
      final StringTokenizer toAddresses = new StringTokenizer(to, " ", false);
      while (toAddresses.hasMoreTokens()) {
        mimeMessage.addRecipient(Message.RecipientType.TO, new InternetAddress(toAddresses.nextToken().trim()));
      }
      // subject
      mimeMessage.setSubject(m_subjectPrefix + " " + subject);
      final MimeBodyPart bodypart = new MimeBodyPart();
      bodypart.setText(htmlMessage, "UTF-8");
      bodypart.setHeader("Content-Type", "text/html");
      if (saveGame != null) {
        final Multipart multipart = new MimeMultipart();
        multipart.addBodyPart(bodypart);
        // add save game
        final FileInputStream fin = new FileInputStream(saveGame);
        final DataSource source = new ByteArrayDataSource(fin, "application/triplea");
        final BodyPart messageBodyPart = new MimeBodyPart();
        messageBodyPart.setDataHandler(new DataHandler(source));
        messageBodyPart.setFileName(saveGameName);
        multipart.addBodyPart(messageBodyPart);
        mimeMessage.setContent(multipart);
      }
      // date
      try {
        mimeMessage.setSentDate(Date.from(Instant.now()));
      } catch (final Exception e) {
        // NoOp - the Date field is simply ignored in this case
      }
      final Transport transport = session.getTransport("smtp");
      if (getUserName() != null) {
        transport.connect(getHost(), getPort(), getUserName(), getPassword());
      } else {
        transport.connect();
      }
      mimeMessage.saveChanges();
      transport.sendMessage(mimeMessage, mimeMessage.getAllRecipients());
      transport.close();
    } catch (final MessagingException e) {
      throw new IOException(e.getMessage());
    }
  }

public boolean blockDelegateExecution(final int timeToWaitMs) throws InterruptedException {
    final boolean rVal = m_readWriteLock.writeLock().tryLock(timeToWaitMs, TimeUnit.MILLISECONDS);
    if (!rVal) {
      if (sm_logger.isLoggable(Level.FINE)) {
        sm_logger.fine("Could not block delegate execution. Read Lock count: " + m_readWriteLock.getReadLockCount()
            + " Write Hold count: " + m_readWriteLock.getWriteHoldCount() + " Queue Length: "
            + m_readWriteLock.getQueueLength() + " Current Thread Has Lock: "
            + m_readWriteLock.isWriteLockedByCurrentThread() + " Has Queued Threads: "
            + m_readWriteLock.hasQueuedThreads() + " Is Write Locked: " + m_readWriteLock.isWriteLocked()
            + " toString: " + m_readWriteLock.toString());
      } else {
        HeadlessGameServer.log("Could not block delegate execution. Read Lock count: "
            + m_readWriteLock.getReadLockCount() + " Write Hold count: " + m_readWriteLock.getWriteHoldCount()
            + " Queue Length: " + m_readWriteLock.getQueueLength() + " Current Thread Has Lock: "
            + m_readWriteLock.isWriteLockedByCurrentThread() + " Has Queued Threads: "
            + m_readWriteLock.hasQueuedThreads() + " Is Write Locked: " + m_readWriteLock.isWriteLocked()
            + " toString: " + m_readWriteLock.toString());
      }
    } else {
      if (sm_logger.isLoggable(Level.FINE)) {
        sm_logger.fine(Thread.currentThread().getName() + " block delegate execution.");
      }
    }
    return rVal;
  }

public void stopGame() {
    // we have already shut down
    if (m_isGameOver) {
      System.out.println("Game previously stopped, cannot stop again.");
      return;
    } else if (HeadlessGameServer.headless()) {
      System.out.println("Attempting to stop game.");
    }
    m_isGameOver = true;
    m_delegateExecutionStoppedLatch.countDown();
    // tell the players (especially the AI's) that the game is stopping, so stop doing stuff.
    for (final IGamePlayer player : m_gamePlayers.values()) {
      // not sure whether to put this before or after we delegate execution block, but definitely before the game loader
      // shutdown
      player.stopGame();
    }
    // block delegate execution to prevent outbound messages to the players while we shut down.
    try {
      if (!m_delegateExecutionManager.blockDelegateExecution(16000)) {
        System.err.println("Could not stop delegate execution.");
        if (HeadlessGameServer.getInstance() != null) {
          HeadlessGameServer.getInstance().printThreadDumpsAndStatus();
        } else {
          ErrorConsole.getConsole().dumpStacks();
        }
        // Try one more time
        if (!m_delegateExecutionManager.blockDelegateExecution(16000)) {
          System.err.println("Exiting...");
          System.exit(-1);
        }
      }
    } catch (final InterruptedException e) {
      ClientLogger.logQuietly(e);
    }
    // shutdown
    try {
      m_delegateExecutionManager.setGameOver();
      getGameModifiedBroadcaster().shutDown();
      m_randomStats.shutDown();
      m_channelMessenger.unregisterChannelSubscriber(m_gameModifiedChannel, IGame.GAME_MODIFICATION_CHANNEL);
      m_remoteMessenger.unregisterRemote(SERVER_REMOTE);
      m_vault.shutDown();
      final Iterator<IGamePlayer> localPlayersIter = m_gamePlayers.values().iterator();
      while (localPlayersIter.hasNext()) {
        final IGamePlayer gp = localPlayersIter.next();
        m_remoteMessenger.unregisterRemote(getRemoteName(gp.getPlayerID(), m_data));
      }
      final Iterator<IDelegate> delegateIter = m_data.getDelegateList().iterator();
      while (delegateIter.hasNext()) {
        final IDelegate delegate = delegateIter.next();
        final Class<? extends IRemote> remoteType = delegate.getRemoteType();
        // if its null then it shouldnt be added as an IRemote
        if (remoteType == null) {
          continue;
        }
        m_remoteMessenger.unregisterRemote(getRemoteName(delegate));
      }
    } catch (final RuntimeException e) {
      ClientLogger.logQuietly(e);
    } finally {
      m_delegateExecutionManager.resumeDelegateExecution();
    }
    m_data.getGameLoader().shutDown();
    if (HeadlessGameServer.headless()) {
      System.out.println("StopGame successful.");
    }
  }

