      PointFileReaderWriter.writeOneToMany(out, new HashMap<>(currentPoints));

      out.flush();
      out.close();
      System.out.println("Data written to :" + new File(fileName).getCanonicalPath());
    } catch (final Exception ex) {
      ClientLogger.logQuietly(ex);
    }
    System.out.println("");
  }

