public static <T> CompletableFuture<T> runWithProgressBar(
      final Frame frame,
      final String message,
      final Callable<T> task) {
    checkNotNull(message);
    checkNotNull(task);

    final CompletableFuture<T> promise = new CompletableFuture<>();
    final SwingWorker<T, ?> worker = new SwingWorker<T, Void>() {
      @Override
      protected T doInBackground() throws Exception {
        return task.call();
      }

      @Override
      protected void done() {
        try {
          promise.complete(get());
        } catch (final ExecutionException e) {
          promise.completeExceptionally(e.getCause());
        } catch (final InterruptedException e) {
          promise.completeExceptionally(e);
          Thread.currentThread().interrupt();
        }
      }
    };
    final ProgressDialog progressDialog = new ProgressDialog(frame, message);
    worker.addPropertyChangeListener(new SwingWorkerCompletionWaiter(progressDialog));
    worker.execute();
    return promise;
  }

private void runSave(final GameData gameData, final HistoryNode node, final File file) {
    SwingComponents.runWithProgressBar(frame, "Saving map snapshot...", () -> {
      save(gameData, node, file);
      return null;
    }).whenComplete((ignore, e) -> {
      SwingUtilities.invokeLater(() -> {
        if (e == null) {
          JOptionPane.showMessageDialog(frame, "Map Snapshot Saved", "Map Snapshot Saved",
              JOptionPane.INFORMATION_MESSAGE);
        } else {
          JOptionPane.showMessageDialog(frame, e.getMessage(), "Error Saving Map Snapshot", JOptionPane.ERROR_MESSAGE);
        }
      });
    });
  }

public static void main(final String[] args) throws Exception {
    handleCommandLineArgs(args);
    final File gameXmlFile = new FileOpen("Select xml file", mapFolderLocation, ".xml").getFile();
    if (gameXmlFile == null) {
      System.out.println("No file selected");
      return;
    }
    final InputStream source = XmlUpdater.class.getResourceAsStream("gameupdate.xslt");
    if (source == null) {
      throw new IllegalStateException("Could not find xslt file");
    }
    final Transformer trans = TransformerFactory.newInstance().newTransformer(new StreamSource(source));

    ByteArrayOutputStream resultBuf;
    try (
        final FileInputStream fileInputStream = new FileInputStream(gameXmlFile);
        final InputStream gameXmlStream = new BufferedInputStream(fileInputStream)) {
      final DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
      factory.setValidating(true);
      // use a dummy game.dtd, this prevents the xml parser from adding default values
      final URL url = XmlUpdater.class.getResource("");
      final String system = url.toExternalForm();
      final Source xmlSource = new StreamSource(gameXmlStream, system);
      resultBuf = new ByteArrayOutputStream();
      trans.transform(xmlSource, new StreamResult(resultBuf));
    }
    gameXmlFile.renameTo(new File(gameXmlFile.getAbsolutePath() + ".backup"));
    final FileOutputStream outStream = new FileOutputStream(gameXmlFile);
    outStream.write(resultBuf.toByteArray());
    outStream.close();
    System.out.println("Successfully updated:" + gameXmlFile);
  }

