protected void saveToFile(final PrintGenerationData printData) throws IOException {
    final GameData gameData = printData.getData();
    final Iterator<GameStep> gameStepIterator = gameData.getSequence().iterator();
    while (gameStepIterator.hasNext()) {
      final GameStep currentStep = gameStepIterator.next();
      if (currentStep.getDelegate() != null && currentStep.getDelegate().getClass() != null) {
        final String delegateClassName = currentStep.getDelegate().getClass().getName();
        if (delegateClassName.equals(InitializationDelegate.class.getName())
            || delegateClassName.equals(BidPurchaseDelegate.class.getName())
            || delegateClassName.equals(BidPlaceDelegate.class.getName())
            || delegateClassName.equals(EndRoundDelegate.class.getName())) {
          continue;
        }
      } else if (currentStep.getName() != null
          && (currentStep.getName().endsWith("Bid") || currentStep.getName().endsWith("BidPlace"))) {
        continue;
      }
      final PlayerID currentPlayerId = currentStep.getPlayerID();
      if (currentPlayerId != null && !currentPlayerId.isNull()) {
        playerSet.add(currentPlayerId);
      }
    }
    FileWriter turnWriter = null;
    printData.getOutDir().mkdir();
    final File outFile = new File(printData.getOutDir(), "General Information.csv");
    turnWriter = new FileWriter(outFile, true);
    turnWriter.write("Turn Order\r\n");
    final Set<PlayerID> noDuplicates = removeDups(playerSet);
    final Iterator<PlayerID> playerIterator = noDuplicates.iterator();
    int count = 1;
    while (playerIterator.hasNext()) {
      final PlayerID currentPlayerId = playerIterator.next();
      turnWriter.write(count + ". " + currentPlayerId.getName() + "\r\n");
      count++;
    }
    turnWriter.close();
  }

protected void saveToFile(final PrintGenerationData printData) {
    final GameData gameData = printData.getData();
    Iterator<PlayerID> playerIterator = gameData.getPlayerList().iterator();
    while (playerIterator.hasNext()) {
      final PlayerID currentPlayer = playerIterator.next();
      final Iterator<Resource> resourceIterator = gameData.getResourceList().getResources().iterator();
      final Map<Resource, Integer> resourceMap = new HashMap<>();
      while (resourceIterator.hasNext()) {
        final Resource currentResource = resourceIterator.next();
        final int amountOfResource = currentPlayer.getResources().getQuantity(currentResource);
        resourceMap.put(currentResource, amountOfResource);
      }
      infoMap.put(currentPlayer, resourceMap);
    }
    FileWriter resourceWriter = null;
    try {
      final File outFile = new File(printData.getOutDir(), "General Information.csv");
      resourceWriter = new FileWriter(outFile, true);
      // Print Title
      final int numResources = gameData.getResourceList().size();
      for (int i = 0; i < numResources / 2 - 1 + numResources % 2; i++) {
        resourceWriter.write(",");
      }
      resourceWriter.write("Resource Chart");
      for (int i = 0; i < numResources / 2 - numResources % 2; i++) {
        resourceWriter.write(",");
      }
      resourceWriter.write("\r\n");
      // Print Resources
      final Iterator<Resource> resourceIterator = gameData.getResourceList().getResources().iterator();
      resourceWriter.write(",");
      while (resourceIterator.hasNext()) {
        final Resource currentResource = resourceIterator.next();
        resourceWriter.write(currentResource.getName() + ",");
      }
      resourceWriter.write("\r\n");
      // Print Player's and Resource Amount's
      playerIterator = gameData.getPlayerList().iterator();
      while (playerIterator.hasNext()) {
        final PlayerID currentPlayer = playerIterator.next();
        resourceWriter.write(currentPlayer.getName());
        final Map<Resource, Integer> resourceMap = infoMap.get(currentPlayer);
        final Iterator<Resource> resIterator = resourceMap.keySet().iterator();
        while (resIterator.hasNext()) {
          final Resource currentResource = resIterator.next();
          final int amountResource = resourceMap.get(currentResource);
          resourceWriter.write("," + amountResource);
        }
        resourceWriter.write("\r\n");
      }
      resourceWriter.write("\r\n");
      resourceWriter.close();
    } catch (final IOException e) {
      ClientLogger.logQuietly(e);
    }
  }

@SuppressWarnings("unchecked")
  public static <T> T translateIntoOtherGameData(final T object, final GameData translateInto) {
    try {
      ByteArrayOutputStream sink = new ByteArrayOutputStream(1024);
      final GameObjectOutputStream out = new GameObjectOutputStream(sink);
      out.writeObject(object);
      out.flush();
      out.close();
      final ByteArrayInputStream source = new ByteArrayInputStream(sink.toByteArray());
      sink = null;
      final GameObjectStreamFactory factory = new GameObjectStreamFactory(translateInto);
      final ObjectInputStream in = factory.create(source);
      try {
        return (T) in.readObject();
      } catch (final ClassNotFoundException ex) {
        // should never happen
        throw new RuntimeException(ex);
      }
    } catch (final IOException ioe) {
      throw new RuntimeException(ioe);
    }
  }

private void exportXmlFile() {
    final JFileChooser chooser = new JFileChooser();
    chooser.setFileSelectionMode(JFileChooser.FILES_ONLY);
    final File rootDir = new File(System.getProperties().getProperty("user.dir"));
    int round = 0;
    try {
      gameData.acquireReadLock();
      round = gameData.getSequence().getRound();
    } finally {
      gameData.releaseReadLock();
    }
    String defaultFileName =
        "xml_" + dateTimeFormatter.format(LocalDateTime.now()) + "_" + gameData.getGameName() + "_round_" + round;
    defaultFileName = IllegalCharacterRemover.removeIllegalCharacter(defaultFileName);
    defaultFileName = defaultFileName + ".xml";
    chooser.setSelectedFile(new File(rootDir, defaultFileName));
    if (chooser.showSaveDialog(frame) != JOptionPane.OK_OPTION) {
      return;
    }
    final String xmlFile;
    try {
      gameData.acquireReadLock();
      final GameDataExporter exporter = new GameDataExporter(gameData);
      xmlFile = exporter.getXML();
    } finally {
      gameData.releaseReadLock();
    }
    try {
      try (final FileWriter writer = new FileWriter(chooser.getSelectedFile())) {
        writer.write(xmlFile);
      }
    } catch (final IOException e1) {
      ClientLogger.logQuietly(e1);
    }
  }

protected void saveToFile(final PlayerID player, final PrintGenerationData printData) {
    final GameData gameData = printData.getData();
    final Collection<Territory> terrCollection =
        Match.getMatches(gameData.getMap().getTerritories(), Matches.territoryHasUnitsOwnedBy(player));
    Iterator<Territory> terrIterator = terrCollection.iterator();
    Iterator<UnitType> availableUnits = gameData.getUnitTypeList().iterator();
    while (terrIterator.hasNext()) {
      final Territory currentTerritory = terrIterator.next();
      final UnitCollection unitsHere = currentTerritory.getUnits();
      final List<Map<UnitType, Integer>> unitPairs = new ArrayList<>();
      while (availableUnits.hasNext()) {
        final UnitType currentUnit = availableUnits.next();
        final int amountHere = unitsHere.getUnitCount(currentUnit, player);
        final Map<UnitType, Integer> innerMap = new HashMap<>();
        innerMap.put(currentUnit, amountHere);
        unitPairs.add(innerMap);
      }
      infoMap.put(currentTerritory, unitPairs);
      availableUnits = gameData.getUnitTypeList().iterator();
    }
    FileWriter countryFileWriter = null;
    final File outFile = new File(printData.getOutDir(), player.getName() + ".csv");
    try {
      countryFileWriter = new FileWriter(outFile, true);
      // Print Title
      final int numUnits = gameData.getUnitTypeList().size();
      for (int i = 0; i < numUnits / 2 - 1 + numUnits % 2; i++) {
        countryFileWriter.write(",");
      }
      countryFileWriter.write("Setup Chart for the " + player.getName());
      for (int i = 0; i < numUnits / 2 - numUnits % 2; i++) {
        countryFileWriter.write(",");
      }
      countryFileWriter.write("\r\n");
      // Print Unit Types
      final Iterator<UnitType> unitIterator = gameData.getUnitTypeList().iterator();
      countryFileWriter.write(",");
      while (unitIterator.hasNext()) {
        final UnitType currentType = unitIterator.next();
        countryFileWriter.write(currentType.getName() + ",");
      }
      countryFileWriter.write("\r\n");
      // Print Territories and Info
      terrIterator =
          Match.getMatches(gameData.getMap().getTerritories(), Matches.territoryHasUnitsOwnedBy(player)).iterator();
      while (terrIterator.hasNext()) {
        final Territory currentTerritory = terrIterator.next();
        countryFileWriter.write(currentTerritory.getName());
        final List<Map<UnitType, Integer>> currentList = infoMap.get(currentTerritory);
        final Iterator<Map<UnitType, Integer>> mapIterator = currentList.iterator();
        while (mapIterator.hasNext()) {
          final Map<UnitType, Integer> currentMap = mapIterator.next();
          final Iterator<UnitType> unitTypeIter = currentMap.keySet().iterator();
          while (unitTypeIter.hasNext()) {
            final UnitType unitTypeHere = unitTypeIter.next();
            final int here = currentMap.get(unitTypeHere);
            countryFileWriter.write("," + here);
          }
        }
        countryFileWriter.write("\r\n");
      }
      countryFileWriter.close();
    } catch (final IOException e) {
      ClientLogger.logError("Failed Saving to File " + outFile.toString(), e);
    }
  }

@Override
  public void startGame(final IGame game, final Set<IGamePlayer> players, final boolean headless)
      throws InvocationTargetException {
    this.game = game;
    if (game.getData().getDelegateList().getDelegate("edit") == null) {
      // An evil hack: instead of modifying the XML, force an EditDelegate by adding one here
      final EditDelegate delegate = new EditDelegate();
      delegate.initialize("edit", "edit");
      game.getData().getDelegateList().addDelegate(delegate);
      if (game instanceof ServerGame) {
        ((ServerGame) game).addDelegateMessenger(delegate);
      }
    }
    final LocalPlayers localPlayers = new LocalPlayers(players);
    if (headless) {
      final IUIContext uiContext = new HeadlessUIContext();
      uiContext.setDefaultMapDir(game.getData());
      uiContext.setLocalPlayers(localPlayers);
      display = new HeadlessDisplay();
      soundChannel = new HeadlessSoundChannel();
      game.addDisplay(display);
      game.addSoundChannel(soundChannel);

      // technically not needed because we won't have any "local human players" in a headless game.
      connectPlayers(players, null);
    } else {
      try {
        SwingUtilities.invokeAndWait(() -> {
          final TripleAFrame frame;
          frame = new TripleAFrame(game, localPlayers);
          display = new TripleADisplay(frame);
          game.addDisplay(display);
          soundChannel = new DefaultSoundChannel(localPlayers);
          game.addSoundChannel(soundChannel);
          frame.setSize(700, 400);
          frame.setVisible(true);
          ClipPlayer.play(SoundPath.CLIP_GAME_START);
          connectPlayers(players, frame);
          frame.setExtendedState(Frame.MAXIMIZED_BOTH);
          frame.toFront();
        });
      } catch (InterruptedException e) {
        ClientLogger.logQuietly(e);
      }
    }

  }

